Create tests/v2/unit/deployment/test_secrets_management.py:
import yaml from pathlib import Path
def test_sops_yaml_exists(): assert Path(".sops.yaml").exists()
def test_sops_yaml_has_required_structure(): config = yaml.safe_load(Path(".sops.yaml").read_text(encoding="utf-8")) assert "creation_rules" in config rules = config["creation_rules"] assert len(rules) >= 1 # Must reference .env files env_rules = [r for r in rules if ".env" in r.get("path_regex", "")] assert env_rules, "No creation rule for .env files found in .sops.yaml" # Must have age or pgp key group for rule in env_rules: has_age = "age" in rule or "key_groups" in rule assert has_age, f"No age key group in rule: {rule}"
def test_setup_dev_sh_exists_and_is_executable(): script = Path("scripts/setup_dev.sh") assert script.exists() content = script.read_text(encoding="utf-8") assert "sops" in content.lower() or "decrypt" in content.lower() assert "setup_dev" in content.lower() or "env" in content.lower()
def test_setup_dev_sh_has_env_validation_step(): content = Path("scripts/setup_dev.sh").read_text(encoding="utf-8") # Must check for required env vars after decrypt assert "MODEL_CACHE_HOST_PATH" in content or "required" in content.lower()
def test_rotate_credentials_is_python_not_sed(): script = Path("scripts/_rotate_credentials.py") assert script.exists() content = script.read_text(encoding="utf-8") # Rule #16: must NOT use regex for parsing .env assert "import re" not in content, "Rule #16 violation: regex banned for .env parsing" assert "sed" not in content, "sed banned — use Python str.split" # Must use str.split or str.partition assert ".split(" in content or ".partition(" in content
def test_rotate_credentials_uses_secrets_module(): content = Path("scripts/_rotate_credentials.py").read_text(encoding="utf-8") assert "import secrets" in content, "Must use secrets.token_hex for credential generation"
def test_env_example_documents_sops_usage(): content = Path(".env.example").read_text(encoding="utf-8") # .env.example should mention SOPS or point to setup_dev.sh assert "sops" in content.lower() or "setup_dev" in content.lower()

Create tests/v2/unit/deployment/test_falco.py:
import yaml from pathlib import Path
FALCO_RULES = Path("deployment/falco/minivess_rules.yaml") FALCO_COMPOSE_SERVICE = "falco"
def test_falco_rules_file_exists(): assert FALCO_RULES.exists()
def test_falco_rules_is_valid_yaml(): rules = yaml.safe_load(FALCO_RULES.read_text(encoding="utf-8")) assert rules is not None
def test_falco_rules_has_minivess_specific_rules(): content = FALCO_RULES.read_text(encoding="utf-8") # Must have rules targeting minivess containers assert "minivess" in content.lower() # Must cover the three ML-specific threat scenarios from issue #551 assert "checkpoints" in content or "checkpoint" in content # model exfiltration assert "spawned" in content.lower() or "shell" in content.lower() # shell spawn
def test_falco_service_in_compose(): compose = yaml.safe_load( Path("deployment/docker-compose.yml").read_text(encoding="utf-8") ) services = compose.get("services", {}) assert FALCO_COMPOSE_SERVICE in services falco = services[FALCO_COMPOSE_SERVICE] assert "security" in falco.get("profiles", [])
def test_falco_service_is_the_only_privileged_service(): """Regression: adding Falco (privileged) must not cause other services to be privileged.""" compose = yaml.safe_load( Path("deployment/docker-compose.yml").read_text(encoding="utf-8") ) for name, svc in compose.get("services", {}).items(): if name == FALCO_COMPOSE_SERVICE: continue # Falco intentionally requires privileged assert not svc.get("privileged", False), \ f"Service '{name}' is unexpectedly privileged after Falco addition"
def test_falco_deployment_claude_md_documents_security_profile(): content = Path("deployment/CLAUDE.md").read_text(encoding="utf-8") assert "falco" in content.lower() assert "--profile security" in content or "profile security" in content.lower()
